734	// 편집 중 Enter → 저장(blur), Escape → 취소
735	document.addEventListener('keydown', function(e) {
736	  const el = document.activeElement;
737	  if (!el.classList.contains('summary-text')) return;
738	  if (e.key === 'Escape') {
739	    el.blur();
740	  }
741	});
742	</script>
